def read():
    try:
        with open(TARGET, encoding="utf-8") as f:
            return f.read()
    except FileNotFoundError:
        sys.exit("ABORT: target not found: " + TARGET + "\n  (run from repo root)")


def forward(text):
    for name, find, repl in EDITS:
        if repl in text:
            sys.exit("ABORT: edit " + name + " already present. "
                     "Run with --reverse first to re-apply cleanly.")
        n = text.count(find)
        if n != 1:
            sys.exit("ABORT: anchor for edit " + name + " found " + str(n)
                     + " times (need exactly 1). The live file has drifted; re-read "
                     "source and update the anchor.")
        text = text.replace(find, repl, 1)
    return text


def backward(text):
    for name, find, repl in EDITS:
        if repl not in text:
            sys.exit("ABORT: edit " + name + " not present; nothing to reverse.")
        text = text.replace(repl, find, 1)
    return text


def diff(a, b):
    return "".join(difflib.unified_diff(
        a.splitlines(keepends=True), b.splitlines(keepends=True),
        fromfile=TARGET + " (current)", tofile=TARGET + " (after)"))


def main():
    ap = argparse.ArgumentParser()
    g = ap.add_mutually_exclusive_group()
    g.add_argument("--apply", action="store_true", help="write the merge")
    g.add_argument("--reverse", action="store_true", help="undo the merge")
    args = ap.parse_args()

    cur = read()
    new = backward(cur) if args.reverse else forward(cur)

    if not (args.apply or args.reverse):
        d = diff(cur, new)
        print(d if d else "(no change)")
        print("\n[DRY RUN] nothing written. Use --apply to write, --reverse to undo.")
        return

    with open(TARGET, "w", encoding="utf-8") as f:
        f.write(new)
    print(("Reversed" if args.reverse else "Applied") + " merge -> " + TARGET)


if __name__ == "__main__":
    main()
